'use client'
import { cn, getLinkComponent, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { type KeyboardEvent, type MouseEvent, type ReactNode, type RefObject } from 'react'
import { usePopover } from '../popover/use-popover'
import styles from './shell-header.module.css'

export interface ShellHeaderBrand {
  prefix?: string
  name: string
  href?: string
}

export interface ShellHeaderNavLink {
  /** Stable React key. Provide when `href`/`label` may repeat (e.g. placeholder `#` links). */
  id?: string
  label: string
  href: string
  active?: boolean
  /** Intercept navigation (e.g. a SPA section switch). Forwarded to the `<a>`. */
  onClick?: ((e: MouseEvent<HTMLAnchorElement>) => void) | undefined
}

export interface ShellHeaderNavMenuItem {
  /** Stable React key. Provide when `href`/`label` may repeat (e.g. placeholder `#` links). */
  id?: string
  label: string
  href: string
  active?: boolean
}

export interface ShellHeaderNavMenu {
  /** Stable React key. Provide when `label` may repeat across menus. */
  id?: string
  label: string
  items: ShellHeaderNavMenuItem[]
}

export type ShellHeaderNavItem = ShellHeaderNavLink | ShellHeaderNavMenu

export interface ShellHeaderAction {
  id: string
  label: string
  icon: ReactNode
  active?: boolean
  onClick?: (() => void) | undefined
}

export interface ShellHeaderLabels {
  skipToContent?: string
  nav?: string
  openMenu?: string
  closeMenu?: string
}

export interface ShellHeaderProps {
  brand?: ShellHeaderBrand | ReactNode
  nav?: ShellHeaderNavItem[]
  actions?: ShellHeaderAction[]
  end?: ReactNode
  onMenuClick?: (() => void) | undefined
  menuExpanded?: boolean
  skipToContentHref?: string | false
  labels?: ShellHeaderLabels
  className?: string | undefined
}

function isBrandObject(brand: ShellHeaderBrand | ReactNode): brand is ShellHeaderBrand {
  return typeof brand === 'object' && brand !== null && 'name' in (brand as object)
}

function isNavMenu(item: ShellHeaderNavItem): item is ShellHeaderNavMenu {
  return 'items' in item
}

function NavMenu({ item }: { item: ShellHeaderNavMenu }) {
  useSignals()
  const LinkComponent = getLinkComponent()
  const { triggerRef, popoverRef, isOpen, anchorName, toggle, close } = usePopover()
  const hasActiveChild = item.items.some((sub) => sub.active)
  const focusFirstOnOpen = useSignal(false)

  // Focus first menuitem when opened via keyboard ArrowDown
  useSignalEffect(() => {
    if (!focusFirstOnOpen.value || !isOpen.value) return
    focusFirstOnOpen.value = false
    const panel = popoverRef.current
    if (!panel) return
    panel.querySelector<HTMLElement>('[role="menuitem"]')?.focus()
  })

  function handleTriggerKeyDown(e: KeyboardEvent<HTMLButtonElement>) {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      if (!isOpen.value) {
        focusFirstOnOpen.value = true
        toggle()
      } else {
        popoverRef.current?.querySelector<HTMLElement>('[role="menuitem"]')?.focus()
      }
    } else if (e.key === 'Escape') {
      e.preventDefault()
      close()
    }
  }

  function handlePanelKeyDown(e: KeyboardEvent<HTMLDivElement>) {
    const items = Array.from(
      popoverRef.current?.querySelectorAll<HTMLElement>('[role="menuitem"]') ?? [],
    )
    const index = items.indexOf(document.activeElement as HTMLElement)
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      items[(index + 1) % items.length]?.focus()
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      items[(index - 1 + items.length) % items.length]?.focus()
    } else if (e.key === 'Escape') {
      close()
      ;(triggerRef.current as HTMLElement | null)?.focus()
    }
  }

  return (
    <li className={styles['navMenuWrapper']}>
      <button
        ref={triggerRef as RefObject<HTMLButtonElement>}
        type="button"
        aria-haspopup="menu"
        aria-expanded={isOpen.value}
        data-state={hasActiveChild ? 'active' : undefined}
        style={{ anchorName } as React.CSSProperties}
        className={styles['navMenuTrigger']}
        onClick={toggle}
        onKeyDown={handleTriggerKeyDown}
      >
        {item.label}
        <svg
          viewBox="0 0 16 16"
          width="12"
          height="12"
          aria-hidden="true"
          className={styles['chevron']}
        >
          <path
            d="M4 6l4 4 4-4"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      </button>
      <div
        ref={popoverRef as RefObject<HTMLDivElement>}
        popover="auto"
        role="menu"
        aria-label={item.label}
        data-state={isOpen.value ? 'open' : 'closed'}
        style={{ positionAnchor: anchorName } as React.CSSProperties}
        className={styles['navMenuPanel']}
        onKeyDown={handlePanelKeyDown}
      >
        {item.items.map((sub, i) => (
          <LinkComponent
            key={sub.id ?? `${i}-${sub.href}`}
            href={sub.href}
            role="menuitem"
            aria-current={sub.active ? 'page' : undefined}
            data-state={sub.active ? 'active' : undefined}
            className={styles['navMenuItem']}
            onClick={close}
          >
            {sub.label}
          </LinkComponent>
        ))}
      </div>
    </li>
  )
}

export function ShellHeader({
  brand,
  nav,
  actions,
  end,
  onMenuClick,
  menuExpanded,
  skipToContentHref = '#cascade-main',
  labels,
  className,
}: ShellHeaderProps) {
  useSignals()
  const LinkComponent = getLinkComponent()
  const navLabel = labels?.nav ?? t(builtin.shellHeader.nav)
  const menuLabel = menuExpanded
    ? (labels?.closeMenu ?? t(builtin.shellHeader.closeMenu))
    : (labels?.openMenu ?? t(builtin.shellHeader.openMenu))

  return (
    <header role="banner" className={cn(styles['header'], className)}>
      {skipToContentHref !== false && (
        <a href={skipToContentHref} className={styles['skipLink']}>
          {labels?.skipToContent ?? t(builtin.shellHeader.skipToContent)}
        </a>
      )}
      {onMenuClick && (
        <button
          type="button"
          aria-label={menuLabel}
          aria-expanded={menuExpanded ?? false}
          className={styles['menuButton']}
          onClick={onMenuClick}
        >
          <svg viewBox="0 0 16 16" width="16" height="16" aria-hidden="true">
            <path
              d="M2 4h12M2 8h12M2 12h12"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
            />
          </svg>
        </button>
      )}
      {brand != null &&
        (isBrandObject(brand) ? (
          <LinkComponent
            href={brand.href ?? '/'}
            aria-label={[brand.prefix, brand.name].filter(Boolean).join(' ')}
            className={styles['brand']}
          >
            {brand.prefix && <span className={styles['brandPrefix']}>{brand.prefix}</span>}
            <span className={styles['brandName']}>{brand.name}</span>
          </LinkComponent>
        ) : (
          <div className={styles['brand']}>{brand}</div>
        ))}
      {nav && nav.length > 0 && (
        <nav aria-label={navLabel} className={styles['nav']}>
          <ul className={styles['navList']}>
            {nav.map((item, i) =>
              isNavMenu(item) ? (
                <NavMenu key={item.id ?? `${i}-${item.label}`} item={item} />
              ) : (
                <li key={item.id ?? `${i}-${item.href}`}>
                  <LinkComponent
                    href={item.href}
                    aria-current={item.active ? 'page' : undefined}
                    data-state={item.active ? 'active' : undefined}
                    className={styles['navLink']}
                    {...(item.onClick ? { onClick: item.onClick } : {})}
                  >
                    {item.label}
                  </LinkComponent>
                </li>
              ),
            )}
          </ul>
        </nav>
      )}
      <div className={styles['spacer']} />
      {actions && actions.length > 0 && (
        <div className={styles['actions']}>
          {actions.map((action) => (
            <button
              key={action.id}
              type="button"
              aria-label={action.label}
              aria-pressed={action.active ?? false}
              title={action.label}
              data-state={action.active ? 'active' : undefined}
              className={styles['action']}
              onClick={action.onClick}
            >
              <span className={styles['actionIcon']} aria-hidden="true">
                {action.icon}
              </span>
            </button>
          ))}
        </div>
      )}
      {end && <div className={styles['end']}>{end}</div>}
    </header>
  )
}

@layer cascivo.component {
  .header {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    block-size: var(--cascivo-shell-header-block-size);
    padding-inline: var(--cascivo-space-3);
    background: var(--cascivo-color-surface);
    border-block-end: 1px solid var(--cascivo-color-border);
    font-family: var(--cascivo-font-sans);
    position: relative;
  }

  .skipLink {
    position: absolute;
    inset-block-start: var(--cascivo-space-2);
    inset-inline-start: var(--cascivo-space-2);
    z-index: 100;
    padding: var(--cascivo-space-2) var(--cascivo-space-3);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    color: var(--cascivo-color-text);
    text-decoration: none;
    font-size: var(--cascivo-text-sm);
    /* Visually hidden until focused */
    clip-path: inset(50%);

    &:focus-visible {
      clip-path: none;
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .menuButton {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 2.5rem;
    block-size: 2.5rem;
    border: none;
    background: transparent;
    border-radius: var(--cascivo-radius-control);
    color: var(--cascivo-color-text);
    cursor: pointer;
    flex-shrink: 0;

    &:hover {
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .brand {
    display: inline-flex;
    align-items: baseline;
    gap: var(--cascivo-space-1);
    color: var(--cascivo-color-text);
    text-decoration: none;
    white-space: nowrap;
    font-size: var(--cascivo-text-sm);
  }

  .brandPrefix {
    font-weight: var(--cascivo-font-normal);
  }

  .brandName {
    font-weight: var(--cascivo-font-semibold);
  }

  .nav {
    min-inline-size: 0;
  }

  .navList {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    margin: 0;
    padding: 0;
    list-style: none;
  }

  .navLink {
    display: inline-flex;
    align-items: center;
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    text-decoration: none;
    white-space: nowrap;
    border-radius: var(--cascivo-radius-control);
    transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-state='active'] {
      color: var(--cascivo-color-text);
      font-weight: var(--cascivo-font-semibold);
      background: var(--cascivo-color-bg-subtle);
    }
  }

  .navMenuWrapper {
    position: relative;
    list-style: none;
  }

  .navMenuTrigger {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    white-space: nowrap;
    transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-state='active'] {
      color: var(--cascivo-color-text);
      font-weight: var(--cascivo-font-semibold);
      background: var(--cascivo-color-bg-subtle);
    }
  }

  .chevron {
    transition: transform var(--cascivo-duration-150) var(--cascivo-ease-out);

    :is([aria-expanded='true']) & {
      transform: rotate(180deg);
    }
  }

  .navMenuPanel {
    position: fixed;
    position-anchor: var(--cascivo-popover-anchor, inherit);
    inset-block-start: anchor(end);
    inset-inline-start: anchor(start);
    margin: var(--cascivo-space-1) 0 0;
    padding: var(--cascivo-space-1);
    min-inline-size: 12rem;
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    box-shadow: var(--cascivo-shadow-md);
    list-style: none;

    translate: 0 0;
    transition:
      translate var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    @starting-style {
      translate: 0 -0.5rem;
    }

    &[data-state='closed'] {
      translate: 0 -0.5rem;
      transition:
        translate var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }
  }

  .navMenuItem {
    display: block;
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    text-decoration: none;
    border-radius: var(--cascivo-radius-item);
    white-space: nowrap;

    &:hover,
    &:focus-visible {
      background: var(--cascivo-color-bg-subtle);
      outline: none;
    }

    &[data-state='active'] {
      background: var(--cascivo-color-active-bg);
      font-weight: var(--cascivo-font-medium);
    }
  }

  .spacer {
    flex: 1;
  }

  .actions {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-1);
  }

  .action {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 2.5rem;
    block-size: 2.5rem;
    border: none;
    border-block-end: 2px solid transparent;
    background: transparent;
    color: var(--cascivo-color-text);
    cursor: pointer;
    border-radius: var(--cascivo-radius-control);

    &:hover {
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-state='active'] {
      border-block-end-color: var(--cascivo-color-accent);
      background: var(--cascivo-color-bg-subtle);
    }
  }

  .actionIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 1.25rem;
    block-size: 1.25rem;
  }

  .end {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    padding-inline-start: var(--cascivo-space-2);
  }
}
